import{_ as d,o as a,c as e,a7 as r}from"./chunks/framework.C5fSpjcB.js";const u=JSON.parse('{"title":"挑战关卡","description":"","frontmatter":{},"headers":[],"relativePath":"stages/challenge.md","filePath":"zh/stages/challenge.md","lastUpdated":1775394001000}'),h={name:"stages/challenge.md"};function o(l,t,i,n,s,b){return a(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="挑战关卡" tabindex="-1">挑战关卡 <a class="header-anchor" href="#挑战关卡" aria-label="Permalink to &quot;挑战关卡&quot;">​</a></h1><p>挑战关卡提供高难度战斗内容和丰厚奖励。</p><h2 id="融灾禁区-erosion-disaster-zone" tabindex="-1">融灾禁区 (Erosion Disaster Zone) <a class="header-anchor" href="#融灾禁区-erosion-disaster-zone" aria-label="Permalink to &quot;融灾禁区 (Erosion Disaster Zone)&quot;">​</a></h2><p>多队伍终局挑战内容，主要「黑色供物」获取来源，含稀有独占奖励。</p><table tabindex="0"><thead><tr><th>属性</th><th>说明</th></tr></thead><tbody><tr><td>类型</td><td>高难挑战</td></tr><tr><td>重置</td><td>每两周 周四15:00</td></tr><tr><td>解锁</td><td>通关主线4-3（原5-4，v1.2降低）</td></tr><tr><td>限制</td><td>不可跨队伍重复使用同一唤醒体/命轮/钥令</td></tr><tr><td>关键奖励</td><td>原初灵核、灵核碎片、黑色贡物</td></tr></tbody></table><h3 id="警戒等级" tabindex="-1">警戒等级 <a class="header-anchor" href="#警戒等级" aria-label="Permalink to &quot;警戒等级&quot;">​</a></h3><table tabindex="0"><thead><tr><th>等级</th><th>特训值范围</th><th>敌人等级</th><th>备注</th></tr></thead><tbody><tr><td>I</td><td>50/55/60/65/70</td><td>50-58</td><td>—</td></tr><tr><td>II</td><td>55/60/65/70/75</td><td>55-63</td><td>—</td></tr><tr><td>III</td><td>60/65/70/75/80</td><td>60-68</td><td>受融灾黑潮影响</td></tr></tbody></table><h3 id="融灾黑潮debuff" tabindex="-1">融灾黑潮debuff <a class="header-anchor" href="#融灾黑潮debuff" aria-label="Permalink to &quot;融灾黑潮debuff&quot;">​</a></h3><table tabindex="0"><thead><tr><th>debuff名称</th><th>效果</th></tr></thead><tbody><tr><td>狂气衰竭</td><td>降低狂气获取</td></tr><tr><td>银钥振荡</td><td>干扰银钥能量</td></tr><tr><td>怒海狂澜</td><td>深海界域特殊效果</td></tr><tr><td>猩红哺育</td><td>血肉界域特殊效果</td></tr><tr><td>彼界终途</td><td>超维界域特殊效果</td></tr><tr><td>来自遗忘</td><td>混沌界域特殊效果</td></tr></tbody></table><h3 id="奖励节点" tabindex="-1">奖励节点 <a class="header-anchor" href="#奖励节点" aria-label="Permalink to &quot;奖励节点&quot;">​</a></h3><p>特训值达到300以上，每档额外获得：黑色贡物x2500 + 蔷薇金券x100,000。III级300特训值的黑色贡物从1500提高为2500。</p><h2 id="幻梦深潜-phantasmal-dive" tabindex="-1">幻梦深潜 (Phantasmal Dive) <a class="header-anchor" href="#幻梦深潜-phantasmal-dive" aria-label="Permalink to &quot;幻梦深潜 (Phantasmal Dive)&quot;">​</a></h2><p>Roguelike爬塔模式，含段位系统。v1.5进行了重大翻新改造。</p><table tabindex="0"><thead><tr><th>属性</th><th>说明</th></tr></thead><tbody><tr><td>类型</td><td>Roguelike排位</td></tr><tr><td>重置</td><td>每周</td></tr><tr><td>掉落</td><td>融蚀之珠(D-Jewels)、银芯</td></tr><tr><td>融蚀之珠公式</td><td>(幻梦等级+2)x100</td></tr></tbody></table><h3 id="roguelike机制" tabindex="-1">Roguelike机制 <a class="header-anchor" href="#roguelike机制" aria-label="Permalink to &quot;Roguelike机制&quot;">​</a></h3><ul><li><strong>地图</strong> — 战争迷雾六角格地图，每日更换。节点类型：战斗/精英/Boss/商店/休息/随机事件/宝藏</li><li><strong>刻印</strong> — 击败普通敌人后获得(3选1)。优先级：妙手 &gt; 灵感 &gt; 算力 &gt; 镜像伙伴 &gt; 回想</li><li><strong>造物</strong> — 击败精英敌人后获得(3选1)。分银/金/诅咒三档。优先级：算力造物 &gt; 狂气 &gt; 暴击率 &gt; 抽牌 &gt; 触腕上限</li><li><strong>黑印</strong> — 战斗掉落，在融痕(交换点)消费。消费优先级：造物 &gt; 觉醒 &gt; 普通刻印</li></ul><h3 id="段位与商店" tabindex="-1">段位与商店 <a class="header-anchor" href="#段位与商店" aria-label="Permalink to &quot;段位与商店&quot;">​</a></h3><table tabindex="0"><thead><tr><th>商店物品</th><th>价格</th></tr></thead><tbody><tr><td>追念羽笔</td><td>800融蚀之珠=5/周</td></tr><tr><td>碎裂余梦</td><td>100融蚀之珠/周</td></tr><tr><td>群星余梦</td><td>25融蚀之珠/周</td></tr></tbody></table><h2 id="相位对弈-phase-chess" tabindex="-1">相位对弈 (Phase Chess) <a class="header-anchor" href="#相位对弈-phase-chess" aria-label="Permalink to &quot;相位对弈 (Phase Chess)&quot;">​</a></h2><p>卡牌PVP对战，仍在Beta测试中。角色练度不影响PVP——所有卡牌以相同强度解锁。</p><table tabindex="0"><thead><tr><th>属性</th><th>说明</th></tr></thead><tbody><tr><td>类型</td><td>PVP排位</td></tr><tr><td>重置</td><td>每周</td></tr><tr><td>解锁</td><td>通关主线3-2</td></tr><tr><td>掉落</td><td>演习徽章、蔷薇金券</td></tr></tbody></table><h3 id="pvp规则" tabindex="-1">PVP规则 <a class="header-anchor" href="#pvp规则" aria-label="Permalink to &quot;PVP规则&quot;">​</a></h3><table tabindex="0"><thead><tr><th>规则</th><th>PVE</th><th>PVP</th></tr></thead><tbody><tr><td>初始手牌</td><td>—</td><td>5张</td></tr><tr><td>换牌</td><td>—</td><td>可自由选择任意张数更换</td></tr><tr><td>每回合抽牌</td><td>4张</td><td>5张</td></tr><tr><td>手牌保留</td><td>回合末弃牌</td><td>手牌保留至下回合</td></tr><tr><td>初始算力</td><td>固定5点</td><td>3点起每回合+1至上限10</td></tr><tr><td>角色练度</td><td>有效</td><td>所有卡牌等强度</td></tr><tr><td>阵亡角色卡</td><td>移除</td><td>变为「泪滴」(0费，恢复10点能量)</td></tr></tbody></table><h3 id="死斗机制" tabindex="-1">死斗机制 <a class="header-anchor" href="#死斗机制" aria-label="Permalink to &quot;死斗机制&quot;">​</a></h3><p>双方算力上限均达到10后自动施加死斗效果：先降低治疗和护盾效果，再将所有治疗和护盾变为1点，强制分出胜负。</p><h3 id="段位" tabindex="-1">段位 <a class="header-anchor" href="#段位" aria-label="Permalink to &quot;段位&quot;">​</a></h3><p>新手段位 → 资深I → 传说 → 相位传奇(最高段)</p><h2 id="其他挑战" tabindex="-1">其他挑战 <a class="header-anchor" href="#其他挑战" aria-label="Permalink to &quot;其他挑战&quot;">​</a></h2><table tabindex="0"><thead><tr><th>挑战名称</th><th>类型</th><th>掉落</th><th>说明</th></tr></thead><tbody><tr><td>无光秘境 (Lightless Realm)</td><td>升星挑战</td><td>无光币</td><td>解锁角色升星(2/3/4/5星)</td></tr><tr><td>界域异效区 (D-Effect Zone)</td><td>挑战副本</td><td>无光币</td><td>额外的无光币获取途径</td></tr><tr><td>秘术统御 (Arcane Dominion)</td><td>挑战副本</td><td>调查徽章</td><td>调查徽章获取途径</td></tr><tr><td>天外之下 (Under the Outer Sky)</td><td>新副本</td><td>—</td><td>v2.0+新增副本玩法</td></tr><tr><td>万象门扉 (Door of All Things)</td><td>限时活动</td><td>命轮「真理之门」等</td><td>限时活动玩法，拥有塔薇/隐世的转轮可提高效率</td></tr></tbody></table>',29)])])}const f=d(h,[["render",o]]);export{u as __pageData,f as default};
